import React, { useEffect, useState } from "react";
import { Form, Button, Col, Row } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";
import Header from "../../components/Headers/Header";

const EditDrugForm = () => {
    const { id } = useParams(); // Lấy ID thuốc từ URL
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [formData, setFormData] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        price: "",
        unit: "",
        description: "",
    });

    // Lấy dữ liệu thuốc theo ID khi mở trang
    useEffect(() => {
        const fetchMedicine = async () => {
            try {
                const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
                setFormData(response.data.data);
                setLoading(false);
            } catch (error) {
                console.error("Lỗi khi lấy dữ liệu thuốc:", error);
                setError("Không tìm thấy thuốc!");
                setLoading(false);
            }
        };

        fetchMedicine();
    }, [id]);

    // Xử lý thay đổi dữ liệu trong form
    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleDescriptionChange = (value) => {
        setFormData({ ...formData, description: value });
    };

    // Gửi dữ liệu chỉnh sửa lên server
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await axios.put(`http://localhost:5001/api/medicine/${id}`, formData);
            alert("Cập nhật thuốc thành công!");
            navigate("/drug"); // Quay lại danh sách thuốc
        } catch (error) {
            console.error("Lỗi khi cập nhật thuốc:", error);
            alert("Cập nhật thất bại! Kiểm tra dữ liệu nhập.");
        }
    };

    // Xử lý thoát (quay lại danh sách thuốc)
    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Chỉnh Sửa Thuốc</h4>
                <Form onSubmit={handleSubmit}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Mã thuốc</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_code"
                                    value={formData.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Tên thuốc</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_name"
                                    value={formData.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>ID Loại thuốc</Form.Label>
                                <Form.Control
                                    type="number"
                                    name="medicine_type_id"
                                    value={formData.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Giá (VNĐ)</Form.Label>
                                <Form.Control
                                    type="number"
                                    name="price"
                                    value={formData.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Đơn vị</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="unit"
                                    value={formData.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Mô tả</Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={formData.description}
                            onChange={handleDescriptionChange}
                        />
                    </Form.Group>

                    <div className="d-flex justify-content-end">
                        <Button variant="secondary" onClick={handleCancel} className="me-2">
                            Thoát
                        </Button>
                        <Button variant="primary" type="submit">
                            Lưu
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrugForm;
